from fastapi import Depends, HTTPException
from fastapi.security import HTTPBearer
import jwt
from functools import lru_cache
import structlog

logger = structlog.get_logger()
security = HTTPBearer()

@lru_cache(maxsize=1)
def get_public_key() -> str:
    """Fetch the OAuth provider's public key for JWT verification."""
    # In production: fetch from the OAuth provider's JWKS endpoint
    return load_public_key_from_vault()

def verify_token(token: str = Depends(security)) -> dict:
    """Verify the JWT and extract the team identity and scopes."""
    try:
        payload = jwt.decode(
            token.credentials, get_public_key(),
            algorithms=['RS256'], audience='alliance-data-products',
        )
        return {
            'team': payload['sub'],           # e.g., 'sc-billing'
            'country': payload['country'],     # e.g., 'sc'
            'scopes': set(payload['scopes']),  # e.g., {'meters:read', 'meters:read:tariff'}
        }
    except jwt.ExpiredSignatureError:
        raise HTTPException(status_code=401, detail='Token expired')
    except jwt.InvalidTokenError as e:
        raise HTTPException(status_code=401, detail=f'Invalid token: {e}')

def require_scope(scope: str):
    """Dependency that checks for a specific scope in the JWT."""
    def checker(auth: dict = Depends(verify_token)):
        if scope not in auth['scopes']:
            logger.warning('access_denied', team=auth['team'], required_scope=scope)
            raise HTTPException(status_code=403, detail=f'Missing scope: {scope}')
        return auth
    return checker

