import functools

class CachedProperty:
    """A property that computes its value on first access and caches it.

    Unlike functools.cached_property, this version:
    - Works with __slots__ (stores in a descriptor-managed dict)
    - Can be invalidated by deleting the attribute
    - Logs the computation time for performance monitoring
    """
    def __init__(self, func):
        self.func = func
        self.attr_name = ''
        functools.update_wrapper(self, func)

    def __set_name__(self, owner, name):
        self.attr_name = name
        self.private_name = f'_cached_{name}'

    def __get__(self, obj, objtype=None):
        if obj is None:
            return self
        try:
            return getattr(obj, self.private_name)
        except AttributeError:
            value = self.func(obj)
            setattr(obj, self.private_name, value)
            return value

    def __delete__(self, obj):
        """Invalidate the cached value."""
        try:
            delattr(obj, self.private_name)
        except AttributeError:
            pass

