        @wraps(func)
        async def wrapper(*args, **kwargs):
            request = kwargs.get('request') or args[0]
            token = request.headers.get('X-Service-Token', '')
            try:
                payload = jwt.decode(token, SERVICE_PUBLIC_KEY, algorithms=['RS256'])
                service_id = payload['sub']       # e.g., 'ie-billing-silver-pipeline'
