from deltalake import DeltaTable
import pyarrow as pa
import structlog

logger = structlog.get_logger()

class TurbineMetadataLookup:
    """In-memory lookup table for turbine metadata, refreshed periodically."""

    def __init__(self, delta_path: str, refresh_interval_s: int = 300):
        self.delta_path = delta_path
        self.refresh_interval = refresh_interval_s
        self._cache: dict[str, dict] = {}
        self._last_refresh = 0.0

    def _refresh_if_stale(self) -> None:
        import time
        if time.time() - self._last_refresh > self.refresh_interval:
            dt = DeltaTable(self.delta_path)
            table = dt.to_pyarrow_table(columns=['turbine_id', 'location', 'capacity_mw',
                                                  'owner_team', 'country', 'grid_zone'])
            self._cache = {
                row['turbine_id']: row
                for row in table.to_pylist()
            }
            self._last_refresh = time.time()
            logger.info('turbine_lookup_refreshed', count=len(self._cache))

    def enrich(self, event: dict) -> dict:
        """Enrich a SCADA event with turbine metadata."""
        self._refresh_if_stale()
        turbine_id = event.get('turbine_id')
        metadata = self._cache.get(turbine_id, {})
        return {**event, **metadata}

# Usage in the SCADA consumer:
